<template lang="html">
  <div class="container" style="width:100%; margin-bottom: 50px;">
    <!-- each row of 4 skills -->
    <div
      class="row p-3"
      v-for="(chunk, index) in skillsChunked"
      :key="'skillchunk' + index"
    >
      <!-- skill in row -->
      <div
        class="col-md-3 text-center"
        v-for="skill in chunk"
        :key="skill.name"
      >
        <img :src="getImage(skill.image)" class="skillImg unselectable" />
        <h3 class="skillTitle">{{ skill.name }}</h3>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  props: {
    skills: Array
  },
  data: function() {
    return {
      publicPath: process.env.BASE_URL
    };
  },
  computed: {
    skillsChunked: function() {
      let out = [];
      let chunk = 4;
      for (let i = 0; i < this.skills.length; i += chunk) {
        out.push(this.skills.slice(i, i + chunk));
      }
      return out;
    }
  },
  methods: {
    getImage: function(name) {
      return this.publicPath + "imgs/resume/" + name;
    }
  }
};
</script>

<style scoped src="bootstrap/dist/css/bootstrap.css"></style>

<style lang="css" scoped>
.skillTitle {
  font-size: 1em;
  padding-top: 0.5em;
  color: var(--midCol);
}

.skillImg {
  height: 3em;
  width: auto;
}
</style>
