<template lang="html">
  <div id="sketchContainer"></div>
</template>

<script>
export default {
  data: function() {
    return {
      canvas: null
    };
  },
  mounted() {
    // display sketch
    let sketch = require("@/assets/js/aboutSketch.js");
    const P5 = require("p5");
    this.canvas = new P5(sketch.main, "sketchContainer");
  },
  beforeDestroy() {
    this.canvas.remove();
  }
};
</script>

<style lang="css" scoped></style>
