let p5;
let header, footer;
let canvas;

let minRad;
let rads = [];
let xstep;
let ystep;
let colNum;
let rowNum;

let waveCenter = {
  pos: null,
  t: null,
  maxDist: 0,
  maxSize: 20,
  canClick: true,
  ringSpeed: 0.001
};

const divide = 30;
// speed for no longer affected dots to shrink
const FALL_RATE = 0.01;
// dot size factor
const SIZE_SCALE = 6;//10;

// noise values
const NOISE_SCALE = 4;
const NOISE_SPEED = 0.015;
const NOISE_SIZE = 0.2;

// alpha of default dot
const BASE_ALPHA = 70;

const DIST_FACTOR = 200;

export function main(_p5) {
  p5 = _p5;

  p5.windowResized = () => {
    canvas.position(0, header.offsetHeight);
    p5.resizeCanvas(
      p5.windowWidth,
      p5.windowHeight - footer.offsetHeight - header.offsetHeight
    );
    makeGrid();
  };

  p5.setup = () => {
    // get size based on displayed space
    header = document.getElementById("navContainer");
    footer = document.getElementById("footer");
    canvas = p5.createCanvas(
      p5.windowWidth,
      p5.windowHeight - header.offsetHeight - footer.offsetHeight
    );
    canvas.position(0, header.offsetHeight);
    canvas.style("z-index", "-1");

    // start making the grid
    makeGrid();

    // move mouse out of the way
    p5.mouseX = -1000;
    p5.mouseY = -1000;
    p5.noStroke();
  };

  p5.draw = () => {
    p5.background("#2b2e30");
    drawGrid();
    // update the wave
    if (waveCenter.pos != null) {
      waveCenter.t += waveCenter.ringSpeed * p5.deltaTime;
      if (waveCenter.t > 1) {
        waveCenter.pos = null;
        waveCenter.canClick = true;
      }
    }
  };

  let drawGrid = () => {
    for (let j = 0; j < rowNum; j++) {
      for (let i = 0; i < colNum; i++) {
        // get position of dot in middle of its cell
        let x = (i + 0.5) * xstep;
        let y = (j + 0.5) * ystep;
        let n = p5.noise(
          i * NOISE_SIZE,
          j * NOISE_SIZE,
          p5.frameCount * NOISE_SPEED
        );
        // get distance from mouse
        let size =
          distSquared(x, y, p5.mouseX, p5.mouseY) / (xstep * DIST_FACTOR);
        // if in affect radius
        if (size <= 1) {
          size = 1 - size;
          p5.fill(255, BASE_ALPHA + size * (255 - BASE_ALPHA));
          size = minRad + size * minRad * SIZE_SCALE;
          rads[j][i] = size;
        } else {
          rads[j][i] -= FALL_RATE * p5.deltaTime;
          size = p5.max(rads[j][i], minRad);
          p5.fill(255, BASE_ALPHA);
        }
        // add ripple
        size += getRippleAmount(x, y);
        p5.circle(x, y, size + n * NOISE_SCALE * minRad);
      }
    }
  };

  let getRippleAmount = (x, y) => {
    if (waveCenter.pos == null) {
      return 0;
    }
    // normalized distance
    let d =
      distSquared(x, y, waveCenter.pos[0], waveCenter.pos[1]) /
      waveCenter.maxDist;
    let size = 0;
    if (d <= 1) {
      // get how far this is from height of ripple
      let strength = 1 - Math.abs(d - waveCenter.t);
      if (strength > 0.85) {
        size = strength * (1 - waveCenter.t) * waveCenter.maxSize;
      }
    }
    return size;
  };

  let distSquared = (x1, y1, x2, y2) => {
    let dx = x2 - x1;
    let dy = y2 - y1;
    return dx * dx + dy * dy;
  };

  let makeGrid = () => {
    colNum = Math.floor(p5.width / divide);

    xstep = p5.width / colNum;
    rowNum = Math.floor(p5.height / xstep);
    minRad = xstep * 0.1;
    // add dots to array
    rads = [];
    for (let j = 0; j < rowNum; j++) {
      rads.push([]);
      for (let i = 0; i < colNum; i++) {
        rads[j].push(minRad);
      }
    }
    ystep = p5.height / rowNum;
    let perc = 0.15;
    if (p5.width < 600) {
      perc = 0.5;
    }
    waveCenter.maxDist = p5.width * perc;
    waveCenter.maxDist *= waveCenter.maxDist;
  };

  // on click set wavecenter if possible
  p5.mouseClicked = () => {
    if (waveCenter.canClick) {
      waveCenter.pos = [p5.mouseX, p5.mouseY];
      waveCenter.t = 0;
      waveCenter.canClick = false;
    }
  };
}
