<template lang="html">
  <div id="projectContainer text-center" style="margin-bottom: 2em;">
    <!-- project info -->
    <div class="container info">
      <div class="row justify-content-center">
        <h1 id="page-title" class="col-lg-auto title text-wrap"  v-html="page.title"></h1>
        <div class="col-lg-5">
          <div class="subtitle">
            <h2>{{ page.subtitle }}</h2>
            <h2 class="tools">{{ tools }}</h2>
          </div>
        </div>
      </div>
    </div>
    <!-- render page content -->
    <div
      class="content"
      v-for="(part, index) in page.content"
      :key="id + index"
    >
      <!-- show videos -->
      <div class="videoWrapper" v-if="part.type === 'video'">
        <iframe
          :src="getVideoLink(part.src)"
          frameborder="0"
          class="videoSettings"
          allow="autoplay; fullscreen"
          allowfullscreen
        >
        </iframe>
      </div>
      <!-- show text -->
      <div class="textContent" v-else-if="part.type === 'text'">
        <div class="container">
          <div class="row">
            <p class="col-md-12" v-html="part.body"></p>
          </div>
        </div>
      </div>
      <!-- show images -->
      <div class="imageContainer" v-else>
        <div class="container">
          <div class="row">
            <img
              class="col-lg-12 projImg mx-auto"
              v-for="imgPack in part.images"
              :key="imgPack.path"
              :src="getImage(imgPack.path)"
              :alt="getAltText(imgPack.path)"
              :style="setResolution(imgPack.res)"
            />
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script src="https://player.vimeo.com/api/player.js"></script>
<script>
export default {
  name: "projectPage",
  props: {
    id: String,
    publicPath: String
  },
  computed: {
    page: function() {
      return require("@/assets/projects/" + this.id + ".json");
    },
    tools: function() {
      return this.page.tools.join(" | ");
    }
  },
  methods: {
    getVideoLink: function(id) {
      return (
        "https://player.vimeo.com/video/" + id + "?color=ffffff&portrait=0"
      );
    },
    getImage: function(path) {
      return this.publicPath + "imgs/projectImages/" + path;
    },
    isOdd: function(i) {
      return i % 2 == 1;
    },
    // get the name of the file and use it as the alt text
    getAltText: function(path) {
      let noExt = path.substring(0, path.lastIndexOf(".") + 1);
      return noExt.split("/").slice(-1);
    },
    // set the max resolution for this image
    setResolution: function(res) {
      return `max-width: ${res[0]}px; max-height: ${res[1]}px;`;
    }
  }
};
</script>

<style scoped src="bootstrap/dist/css/bootstrap.css"></style>

<style lang="css" scoped>
/* ////  page info  ///// */
.title {
  font-size: 3em;
  padding-top: 0%;
  max-width: 50%;
  padding-bottom: 0%;
}

#projectContainer {
  margin-bottom: 2em;
  width: 80%;
  /*padding-left: 10%;*/
}

.subtitle {
  width: 100%;
  position: relative;
  padding-top: 0.25em;
}
.subtitle > h2 {
  font-size: 1.25em;
  font-weight: 300;
}
.tools {
  color: var(--midCol);
}
.info {
  padding-top: 1.5em;
}

/* ////  videos  ///// */
.videoSettings {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
}

/* style="padding:54.06% 0 0 0;position:relative;" */
.videoWrapper {
  margin-top: 1em;
  margin-bottom: 1em;
  padding: 33% 0 0 0;
  position: relative;
  /* margin: auto; */
  /*margin-left: 15%;*/
  display: block;
  /*    max-height: 75%;  
    max-width: 75%;*/

  height: auto;
  width: auto;
  overflow: hidden;
}

/* ////  text  ///// */
.textContent {
  font-size: 1.25em;
  padding-top: 1em;
  padding-bottom: 1em;
}

/* ////  images  ///// */
.projImg {
  padding-top: 1em;
  padding-bottom: 1em;
  /*max-width: 300px;*/
  max-width: 100%;
  max-height: 100%;
  /*width: 50%;*/
  /*height: auto;*/
}

@media (max-width: 500px) {
  .videoWrapper {
    padding: 50% 0 0 0;
  }

  .projImg {
    max-width: 100%;
    max-height: 100%;
  }

  .title {
    max-width: 100%;
  }
}
</style>
